// ============================================================================
// Helper Functions
// ============================================================================

// Set repo to detached HEAD state at given SHA
// Must close and reopen repo after calling this
static bool set_detached_head(const wchar_t* repo_path, const char* sha) {
    wchar_t head_path[Git::MAX_PATH_LEN];
    swprintf_s(head_path, L"%s\\.git\\HEAD", repo_path);

    char content[64];
    snprintf(content, sizeof(content), "%s\n", sha);

    return write_file_atomic(head_path, content, strlen(content));
}

// Read the branch ref file to verify it was updated
static bool read_branch_ref(const wchar_t* repo_path, const char* branch_name, char* out_sha) {
    wchar_t ref_path[Git::MAX_PATH_LEN];
    swprintf_s(ref_path, L"%s\\.git\\refs\\heads\\%S", repo_path, branch_name);

    MemoryMap* map = mmap_open(ref_path);
    if (!map) {
        return false;
    }

    // Ref file contains SHA followed by newline
    size_t sha_len = (map->size < 40) ? map->size : 40;
    memcpy(out_sha, map->data, sha_len);
    out_sha[sha_len] = '\0';

    mmap_close(map);
    return true;
}

// Read HEAD file directly (for detached HEAD verification)
static bool read_head_file(const wchar_t* repo_path, char* out_content, size_t max_len) {
    wchar_t head_path[Git::MAX_PATH_LEN];
    swprintf_s(head_path, L"%s\\.git\\HEAD", repo_path);

    MemoryMap* map = mmap_open(head_path);
    if (!map) {
        return false;
    }

    size_t copy_len = (map->size < max_len - 1) ? map->size : max_len - 1;
    memcpy(out_content, map->data, copy_len);
    out_content[copy_len] = '\0';

    mmap_close(map);
    return true;
}

