TEST(amend_root_commit) {
    if (!create_write_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_write_test_repo)) {
        cleanup_write_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    // Get the initial commit (root - has no parent)
    const char* initial_commit_sha = fixture_sha_commit1();

    // Set HEAD to root commit and reopen repo
    git_repo_close(&repo);
    TEST_ASSERT_TRUE(set_detached_head(g_write_test_repo, initial_commit_sha));
    TEST_ASSERT_TRUE(git_repo_open(&repo, g_write_test_repo));
    TEST_ASSERT_TRUE(repo.head_detached);

    // Verify we're on a root commit (no parent)
    GitCommit root_commit = {};
    TEST_ASSERT_TRUE(git_read_commit(&repo, repo.head_sha, &root_commit));
    TEST_ASSERT_EQ(strlen(root_commit.parent_sha), 0);

    // Perform amend on root commit
    bool result = git_commit(&repo, "Amended root commit", true);
    TEST_ASSERT_TRUE(result);

    // New commit should also have no parent
    GitCommit new_commit = {};
    TEST_ASSERT_TRUE(git_read_commit(&repo, repo.head_sha, &new_commit));
    TEST_ASSERT_EQ(strlen(new_commit.parent_sha), 0);

    git_repo_close(&repo);
    cleanup_write_test_repo();
}

TEST(amend_detached_head) {
    if (!create_write_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_write_test_repo)) {
        cleanup_write_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    // Record current HEAD SHA
    char original_sha[41];
    strcpy_s(original_sha, repo.head_sha);

    // Detach HEAD at current commit
    git_repo_close(&repo);
    TEST_ASSERT_TRUE(set_detached_head(g_write_test_repo, original_sha));
    TEST_ASSERT_TRUE(git_repo_open(&repo, g_write_test_repo));

    // Verify detached state
    TEST_ASSERT_TRUE(repo.head_detached);
    TEST_ASSERT_STREQ(repo.head_sha, original_sha);

    // Perform amend in detached HEAD state
    bool result = git_commit(&repo, "Amended in detached HEAD", true);
    TEST_ASSERT_TRUE(result);

    // Verify HEAD file now contains new SHA directly (not ref:)
    char head_content[128] = {};
    TEST_ASSERT_TRUE(read_head_file(g_write_test_repo, head_content, sizeof(head_content)));

    // HEAD should contain the new SHA, not the original
    TEST_ASSERT_STRNE(repo.head_sha, original_sha);
    // HEAD file should start with new SHA (not "ref:")
    TEST_ASSERT_TRUE(strncmp(head_content, repo.head_sha, 40) == 0);

    git_repo_close(&repo);
    cleanup_write_test_repo();
}

TEST(amend_chain) {
    if (!create_write_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_write_test_repo)) {
        cleanup_write_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    // Get original HEAD's parent (the "grandparent")
    GitCommit original_head = {};
    TEST_ASSERT_TRUE(git_read_commit(&repo, repo.head_sha, &original_head));
    char grandparent_sha[41];
    strcpy_s(grandparent_sha, original_head.parent_sha);

    // First amend
    bool result1 = git_commit(&repo, "First amend", true);
    TEST_ASSERT_TRUE(result1);
    char first_amend_sha[41];
    strcpy_s(first_amend_sha, repo.head_sha);

    // Verify first amend's parent is grandparent
    GitCommit first_amend = {};
    TEST_ASSERT_TRUE(git_read_commit(&repo, first_amend_sha, &first_amend));
    TEST_ASSERT_STREQ(first_amend.parent_sha, grandparent_sha);

    // Second amend
    bool result2 = git_commit(&repo, "Second amend", true);
    TEST_ASSERT_TRUE(result2);

    // Verify second amend's parent is STILL grandparent (not first_amend_sha)
    GitCommit second_amend = {};
    TEST_ASSERT_TRUE(git_read_commit(&repo, repo.head_sha, &second_amend));
    TEST_ASSERT_STREQ(second_amend.parent_sha, grandparent_sha);
    TEST_ASSERT_STRNE(second_amend.parent_sha, first_amend_sha);

    git_repo_close(&repo);
    cleanup_write_test_repo();
}

